    def _insertion_sort(a, lo, hi):
        for i in range(lo + 1, hi + 1):
            key = a[i]
            j = i - 1
            while j >= lo and a[j] > key:
                a[j + 1] = a[j]
                j -= 1
            a[j + 1] = key

    def _median_of_three(a, lo, hi):
        mid = (lo + hi) // 2
        if a[lo] > a[mid]:
            a[lo], a[mid] = a[mid], a[lo]
        if a[lo] > a[hi]:
            a[lo], a[hi] = a[hi], a[lo]
        if a[mid] > a[hi]:
            a[mid], a[hi] = a[hi], a[mid]
        a[mid], a[hi - 1] = a[hi - 1], a[mid]
        return a[hi - 1]

    def _quicksort(a, lo, hi):
        while hi - lo > 16:
            pivot = _median_of_three(a, lo, hi)
            i = lo
            j = hi - 1
            while True:
                i += 1
                while a[i] < pivot:
                    i += 1
                j -= 1
                while a[j] > pivot:
                    j -= 1
                if i >= j:
                    break
                a[i], a[j] = a[j], a[i]
            a[i], a[hi - 1] = a[hi - 1], a[i]
            if i - lo < hi - i:
                _quicksort(a, lo, i - 1)
                lo = i + 1
            else:
                _quicksort(a, i + 1, hi)
                hi = i - 1
        _insertion_sort(a, lo, hi)

    if len(result) > 1:
        _quicksort(result, 0, len(result) - 1)
    return result

def fast_sort(arr):
    result = arr[:]
    n = len(result)
    if n <= 1:
        return result

    def _insertion_sort(a, lo, hi):
        for i in range(lo + 1, hi + 1):
            key = a[i]
            j = i - 1
            while j >= lo and a[j] > key:
                a[j + 1] = a[j]
                j -= 1
            a[j + 1] = key

    # Iterative quicksort with explicit stack
    stack = [(0, n - 1)]
    while stack:
        lo, hi = stack.pop()
        if hi - lo <= 16:
            _insertion_sort(result, lo, hi)
            continue
        # Median-of-three pivot
        mid = (lo + hi) // 2
        if result[lo] > result[mid]:
            result[lo], result[mid] = result[mid], result[lo]
        if result[lo] > result[hi]:
            result[lo], result[hi] = result[hi], result[lo]
        if result[mid] > result[hi]:
            result[mid], result[hi] = result[hi], result[mid]
        result[mid], result[hi - 1] = result[hi - 1], result[mid]
        pivot = result[hi - 1]
        i = lo
        j = hi - 1
        while True:
            i += 1
            while result[i] < pivot:
                i += 1
            j -= 1
            while result[j] > pivot:
                j -= 1
            if i >= j:
                break
            result[i], result[j] = result[j], result[i]
        result[i], result[hi - 1] = result[hi - 1], result[i]
        # Push larger partition first for better stack behavior
        if i - lo > hi - i:
            stack.append((lo, i - 1))
            stack.append((i + 1, hi))
        else:
            stack.append((i + 1, hi))
            stack.append((lo, i - 1))
    return result

def fast_sort(arr):
    n = len(arr)
    if n <= 1:
        return arr[:]
    if n <= 32:
        result = arr[:]
        for i in range(1, n):
            key = result[i]
            j = i - 1
            while j >= 0 and result[j] > key:
                result[j + 1] = result[j]
                j -= 1
            result[j + 1] = key
        return result

    # Radix sort with base 65536 (16-bit digits) - only 2 passes for 32-bit ints
    min_val = min(arr)
    if min_val < 0:
        work = [x - min_val for x in arr]
    else:
        work = arr[:]

    max_val = max(work)
    buf = [0] * n

    # Pass 1: lower 16 bits
    count = [0] * 65537
    for x in work:
        count[(x & 0xFFFF) + 1] += 1
    for i in range(1, 65537):
        count[i] += count[i - 1]
    for x in work:
        digit = x & 0xFFFF
        buf[count[digit]] = x
        count[digit] += 1
    work, buf = buf, work

    # Pass 2: upper 16 bits (only if needed)
    if max_val > 0xFFFF:
        count = [0] * 65537
        for x in work:
            count[((x >> 16) & 0xFFFF) + 1] += 1
        for i in range(1, 65537):
            count[i] += count[i - 1]
        for x in work:
            digit = (x >> 16) & 0xFFFF
            buf[count[digit]] = x
            count[digit] += 1
        work, buf = buf, work

    if min_val < 0:
        return [x + min_val for x in work]
    return work

